function equals(Currency currency, Currency other) pure returns (bool) {
    return Currency.unwrap(currency) == Currency.unwrap(other);
}

function greaterThan(Currency currency, Currency other) pure returns (bool) {
    return Currency.unwrap(currency) > Currency.unwrap(other);
}

function lessThan(Currency currency, Currency other) pure returns (bool) {
    return Currency.unwrap(currency) < Currency.unwrap(other);
}

if (balance > 0) {
  if (!suppressRevert) {
    // Perform the transfer and pass along the returned boolean (or revert).
    success = token.transfer(recipient, balance);
  } else {
    // Attempt transfer with 1/2 gas, allow reverts, and return call status.
    (success, ) = address(token).call.gas(gasleft() / 2)(
      abi.encodeWithSelector(token.transfer.selector, recipient, balance)
    );
  }
} else {
  // Skip the transfer and return true as long as the balance check worked.
  success = balanceCheckWorked;
}

if (additionalTokensValue > 0) {

    //Emit TokensBought event when adding tokens at upgrade
    uint256 tokensBought = tokenCollector.getTokens(additionalTokensValue, minTokensOut);
    totalTokens += tokensBought;

    rewardDistributor.distributeRewards(additionalTokensValue, 1, nftId, finalLevel);
    emit TokensBought(nftId, additionalTokensValue, tokensBought, finalLevel);
}

if (processFollowParams.followModule != address(0)) {
    processFollowModuleReturnData = IFollowModule(processFollowParams.followModule).processFollow(
        processFollowParams.followerProfileId,
        processFollowParams.followTokenId,
        processFollowParams.transactionExecutor,
        processFollowParams.idOfProfileToFollow,
        processFollowParams.followModuleData
    );
}

if (
    // If profile is following and requestor is Owner/Delegated Executor of the follower profile, allow access
    ILensHub(LENS_HUB).isFollowing(followerProfileId, profileId) &&
    _isOwnerOrDelegatedExecutor(requestorAddress, followerProfileId)
) {
    return true;
} else {
    // If not following, but is the Owner/Delegated Executor of the target profile, then still allow access
    return _isOwnerOrDelegatedExecutor(requestorAddress, profileId);
}

if (
    _dataByPublicationByProfile[processCollectParams.publicationCollectedProfileId][
        processCollectParams.publicationCollectedId
    ].followerOnly
) {
    FollowValidationLib.validateIsFollowingOrSelf({
        hub: HUB,
        followerProfileId: processCollectParams.collectorProfileId,
        followedProfileId: processCollectParams.publicationCollectedProfileId
    });
}

if (style) {
    // transfer shares into this contract
    asset.safeTransferFrom(msg.sender, address(this), assets);

    asset.safeApprove(msg.sender, assets);

    // Try to re-enter into cellar via deposit
    ERC4626(msg.sender).deposit(assets, receiver);

    // This return should never be hit because the above deposit calls fails from re-entrancy.
    return 0;
} else {
    Cellar cellar = Cellar(msg.sender);
    stdstore.target(address(cellar)).sig(cellar.totalSupply.selector).checked_write(cellar.totalSupply() + 1);
    return 0;
}

if (_collateralToLiquidate != _lenderCollateralTokens) {
    address _borrower = poolConstants.borrower;
    _withdraw(
        poolConstants.collateralAsset,
        poolConstants.borrower,
        _poolSavingsStrategy,
        _lenderCollateralTokens.sub(_collateralToLiquidate),
        false,
        false
    );
    emit CollateralWithdrawn(_borrower, _lenderCollateralTokens.sub(_collateralToLiquidate));
}

if (isConfirmed(transactionId)) {
    Transaction storage txn = transactions[transactionId];
    txn.executed = true;
    if (
        external_call(
            txn.destination,
            txn.value,
            txn.data.length,
            txn.data
        )
    ) emit Execution(transactionId);
    else {
        emit ExecutionFailure(transactionId);
        txn.executed = false;
    }
}

if (insured) {
    position.debtAmountForRepurchase = debtAmount;
    position.liquidatedAt = block.timestamp;
    position.liquidator = msg.sender;
} else {
    // transfer nft to liquidator
    positionOwner[_nftIndex] = address(0);
    delete positions[_nftIndex];
    positionIndexes.remove(_nftIndex);
    nftContract.safeTransferFrom(address(this), msg.sender, _nftIndex);
}

if (s_dynamicConfig.destDataAvailabilityMultiplierBps > 0) {
  dataAvailabilityCost = _getDataAvailabilityCost(
    // Parse the data availability gas price stored in the higher-order 112 bits of the encoded gas price.
    uint112(packedGasPrice >> Internal.GAS_PRICE_BITS),
    message.data.length,
    message.tokenAmounts.length,
    tokenTransferBytesOverhead
  );
}

claimCondition = ClaimCondition({
    startTimestamp: _condition.startTimestamp,
    maxClaimableSupply: _condition.maxClaimableSupply,
    supplyClaimed: supplyClaimedAlready,
    quantityLimitPerWallet: _condition.quantityLimitPerWallet,
    merkleRoot: _condition.merkleRoot,
    pricePerToken: _condition.pricePerToken,
    currency: _condition.currency,
    metadata: _condition.metadata
});

ClaimCondition memory updatedCondition = ClaimCondition({
    startTimestamp: _condition.startTimestamp,
    maxClaimableSupply: _condition.maxClaimableSupply,
    supplyClaimed: supplyClaimedAlready,
    quantityLimitPerWallet: _condition.quantityLimitPerWallet,
    merkleRoot: _condition.merkleRoot,
    pricePerToken: _condition.pricePerToken,
    currency: _condition.currency,
    metadata: _condition.metadata
});

struct Auction {
    uint256 auctionId;
    uint256 tokenId;
    uint256 quantity;
    uint256 minimumBidAmount;
    uint256 buyoutBidAmount;
    uint64 timeBufferInSeconds;
    uint64 bidBufferBps;
    uint64 startTimestamp;
    uint64 endTimestamp;
    address auctionCreator;
    address assetContract;
    address currency;
    TokenType tokenType;
    Status status;
}

struct PooledCreditLineConstants {
    uint128 borrowLimit;
    uint128 borrowRate;
    uint256 idealCollateralRatio;
    address borrower;
    address borrowAsset;
    address collateralAsset;
    uint256 startsAt;
    uint256 endsAt;
    uint256 defaultsAt;
    address borrowAssetStrategy;
    address collateralAssetStrategy;
    uint256 gracePenaltyRate;
}

struct PoolConstants {
    uint64 loanStartTime;
    uint64 loanWithdrawalDeadline;
    uint64 noOfRepaymentIntervals;
    uint64 repaymentInterval;
    address borrower;
    address collateralAsset;
    address borrowAsset;
    address poolSavingsStrategy; // invest contract
    address lenderVerifier;
    uint256 borrowRate;
    uint256 idealCollateralRatio;
    uint256 borrowAmountRequested;
}

if (_borrowerInterestSharesForLender != 0) {
    pooledCLVariables[_id].lenders[_lender].borrowerInterestSharesWithdrawn = pooledCLVariables[_id]
        .lenders[_lender]
        .borrowerInterestSharesWithdrawn
        .add(_borrowerInterestSharesForLender);
    pooledCLVariables[_id].borrowerInterestSharesWithdrawn = pooledCLVariables[_id].borrowerInterestSharesWithdrawn.add(
        _borrowerInterestSharesForLender
    );
}

if(block.timestamp > startDropTimestamp + dropDecreaseDuration) {
    // Set the current DropPerSecond as the end value
    // Plus allows to be updated if the end value is later updated
    if(currentDropPerSecond != endDropPerSecond) {
        currentDropPerSecond = endDropPerSecond;
        lastDropUpdate = block.timestamp;
    }

    return endDropPerSecond;
}

constructor(address conduitController) {
    // Get the conduit creation code and runtime code hashes from the
    // supplied conduit controller and set them as an immutable.
    ConduitControllerInterface controller = ConduitControllerInterface(
        conduitController
    );
    (_CONDUIT_CREATION_CODE_HASH, _CONDUIT_RUNTIME_CODE_HASH) = controller
        .getConduitCodeHashes();

    // Set the supplied conduit controller as an immutable.
    _CONDUIT_CONTROLLER = controller;
}

PoolId id = key.toId();

        tick = _pools[id].initialize(sqrtPriceX96, lpFee);

        // event is emitted before the afterInitialize call to ensure events are always emitted in order
        // emit all details of a pool key. poolkeys are not saved in storage and must always be provided by the caller
        // the key's fee may be a static fee or a sentinel to denote a dynamic fee.
        emit Initialize(id, key.currency0, key.currency1, key.fee, key.tickSpacing, key.hooks, sqrtPriceX96, tick);

        key.hooks.afterInitialize(key, sqrtPriceX96, tick);
    }

return
            _multiplexBatchSellPrivate(
                BatchSellParams({
                    inputToken: inputToken,
                    outputToken: outputToken,
                    sellAmount: sellAmount,
                    calls: calls,
                    useSelfBalance: false,
                    recipient: msg.sender,
                    payer: msg.sender
                }),
                minBuyAmount
            );

bytes memory resultData = wallet.executeDelegateCall(
    // The call target.
    transformer,
    // Call data.
    abi.encodeWithSelector(
        IERC20Transformer.transform.selector,
        IERC20Transformer.TransformContext({
            sender: msg.sender,
            recipient: recipient,
            data: transformation.data
        })
    )
);

struct Info {
    // the amount of liquidity owned by this position
    uint128 liquidity;
    // fee growth per unit of liquidity as of the last update to liquidity or fees owed
    uint256 feeGrowthInside0LastX128;
    uint256 feeGrowthInside1LastX128;
    // the fees owed to the position owner in token0/token1
    uint128 tokensOwed0;
    uint128 tokensOwed1;
}

if (currentFollowerProfileId != 0) {
    // Provided follow token is unwrapped.
    // It has a follower profile set already, it can only be used to follow if that profile was burnt.
    return
        _followWithUnwrappedTokenFromBurnedProfile({
            followerProfileId: followerProfileId,
            followTokenId: followTokenId,
            currentFollowerProfileId: currentFollowerProfileId,
            transactionExecutor: transactionExecutor
        });
}
